import{_ as e,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Продвинутое использование: глубокая настройка и оптимизация | Руководство opencode-notify","description":"Изучите расширенные настройки opencode-notify: справочник конфигурации, тихие часы, определение терминала и лучшие практики. Оптимизируйте уведомления под свои потребности для повышения продуктивности.","frontmatter":{"title":"Продвинутое использование: глубокая настройка и оптимизация | Руководство opencode-notify","sidebarTitle":"Настройте уведомления под себя","subtitle":"Продвинутое использование: глубокая настройка и оптимизация","description":"Изучите расширенные настройки opencode-notify: справочник конфигурации, тихие часы, определение терминала и лучшие практики. Оптимизируйте уведомления под свои потребности для повышения продуктивности.","tags":["Продвинутое","Конфигурация","Оптимизация"],"prerequisite":["start-quick-start","start-how-it-works"],"order":3},"headers":[],"relativePath":"ru/kdcokenny/opencode-notify/advanced/index.md","filePath":"ru/kdcokenny/opencode-notify/advanced/index.md"}'),i={name:"ru/kdcokenny/opencode-notify/advanced/index.md"};function n(l,t,d,c,s,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="продвинутое-использование-глубокая-настроика-и-оптимизация" tabindex="-1">Продвинутое использование: глубокая настройка и оптимизация <a class="header-anchor" href="#продвинутое-использование-глубокая-настроика-и-оптимизация" aria-label="Permalink to &quot;Продвинутое использование: глубокая настройка и оптимизация&quot;">​</a></h1><p>Этот раздел поможет вам освоить расширенные возможности opencode-notify, глубже понять параметры конфигурации, оптимизировать работу уведомлений и настроить их поведение под ваши потребности.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуем изучать материалы этого раздела в следующем порядке:</p><h3 id="_1-справочник-конфигурации" tabindex="-1">1. <a href="./config-reference/">Справочник конфигурации</a> <a class="header-anchor" href="#_1-справочник-конфигурации" aria-label="Permalink to &quot;1. [Справочник конфигурации](./config-reference/)&quot;">​</a></h3><p>Полный обзор всех доступных параметров конфигурации и их назначения.</p><ul><li>Освойте структуру и синтаксис файла конфигурации</li><li>Изучите методы настройки звуков уведомлений</li><li>Поймите сценарии использования переключателя уведомлений для дочерних сессий</li><li>Узнайте, как переопределить тип терминала</li></ul><h3 id="_2-подробно-о-тихих-часах" tabindex="-1">2. <a href="./quiet-hours/">Подробно о тихих часах</a> <a class="header-anchor" href="#_2-подробно-о-тихих-часах" aria-label="Permalink to &quot;2. [Подробно о тихих часах](./quiet-hours/)&quot;">​</a></h3><p>Научитесь настраивать тихие часы, чтобы избежать отвлечений в определённое время.</p><ul><li>Настройка времени начала и окончания тихих часов</li><li>Обработка тихих часов, переходящих через полночь (например, 22:00 - 08:00)</li><li>Временное отключение режима тишины при необходимости</li><li>Понимание приоритета тихих часов относительно других правил фильтрации</li></ul><h3 id="_3-принципы-определения-терминала" tabindex="-1">3. <a href="./terminal-detection/">Принципы определения терминала</a> <a class="header-anchor" href="#_3-принципы-определения-терминала" aria-label="Permalink to &quot;3. [Принципы определения терминала](./terminal-detection/)&quot;">​</a></h3><p>Глубокое понимание механизма автоматического определения терминала.</p><ul><li>Узнайте, как плагин распознаёт более 37 эмуляторов терминала</li><li>Поймите реализацию определения фокуса на платформе macOS</li><li>Освойте методы ручного указания типа терминала</li><li>Разберитесь в поведении по умолчанию при неудачном определении</li></ul><h3 id="_4-продвинутые-приемы" tabindex="-1">4. <a href="./advanced-usage/">Продвинутые приёмы</a> <a class="header-anchor" href="#_4-продвинутые-приемы" aria-label="Permalink to &quot;4. [Продвинутые приёмы](./advanced-usage/)&quot;">​</a></h3><p>Освойте техники конфигурации и лучшие практики.</p><ul><li>Стратегии конфигурации для предотвращения спама уведомлений</li><li>Настройка поведения уведомлений под ваш рабочий процесс</li><li>Рекомендации по конфигурации для многооконных и многотерминальных сред</li><li>Советы по оптимизации производительности и устранению неполадок</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Перед изучением этого раздела рекомендуем завершить следующие базовые материалы:</p><ul><li>✅ <strong>Быстрый старт</strong>: завершите установку плагина и базовую настройку</li><li>✅ <strong>Принцип работы</strong>: поймите основные функции плагина и механизм прослушивания событий</li><li>✅ <strong>Особенности платформ</strong> (опционально): узнайте о специфических функциях вашей платформы</li></ul><div class="tip custom-block"><p class="custom-block-title">Рекомендация по обучению</p><p>Если вы просто хотите настроить звуки уведомлений или установить тихие часы, можете сразу перейти к соответствующей странице. При возникновении вопросов всегда можно обратиться к справочнику конфигурации.</p></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения этого раздела вы можете продолжить исследование:</p><ul><li><strong><a href="./../../faq/troubleshooting/">Устранение неполадок</a></strong>: решение распространённых проблем и сложных случаев</li><li><strong><a href="./../../faq/common-questions/">Часто задаваемые вопросы</a></strong>: ответы на популярные вопросы пользователей</li><li><strong><a href="./../../appendix/event-types/">Описание типов событий</a></strong>: глубокое изучение всех типов событий, отслеживаемых плагином</li><li><strong><a href="./../../appendix/config-file-example/">Примеры файлов конфигурации</a></strong>: полные примеры конфигурации с комментариями</li></ul><hr><details><summary><strong>Нажмите, чтобы посмотреть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Определение интерфейса конфигурации</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr><tr><td>Конфигурация по умолчанию</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L56-L68" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>56-68</td></tr><tr><td>Загрузка конфигурации</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>Проверка тихих часов</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>Определение терминала</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>Сопоставление имён процессов терминалов</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L71-L84" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>71-84</td></tr></tbody></table><p><strong>Ключевые интерфейсы</strong>:</p><ul><li><code>NotifyConfig</code>: интерфейс конфигурации, содержащий все настраиваемые параметры</li><li><code>quietHours</code>: конфигурация тихих часов (enabled/start/end)</li><li><code>sounds</code>: конфигурация звуков (idle/error/permission)</li><li><code>terminal</code>: переопределение типа терминала (опционально)</li></ul><p><strong>Ключевые константы</strong>:</p><ul><li><code>DEFAULT_CONFIG</code>: значения по умолчанию для всех параметров конфигурации</li><li><code>TERMINAL_PROCESS_NAMES</code>: таблица сопоставления названий терминалов с именами процессов macOS</li></ul></details>',25)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
